parameters.jsCode:
const body = $input.first().json.body || $input.first().json;

// Normalize payload from multiple sources
// Supports: Intercom, Zendesk, email form, Slack app, custom web form
let normalized = {};

if (body.type === 'conversation.user.created' || body.data?.item?.type === 'conversation') {
  // Intercom format
  const conv = body.data?.item || body;
  normalized = {
    source: 'intercom',
    externalId: conv.id,
    email: conv.source?.author?.email || '',
    name: conv.source?.author?.name || '',
    message: conv.source?.body || '',
    subject: conv.source?.subject || 'Intercom Chat',
    tags: (conv.tags?.tags || []).map(t => t.name).join(', '),
    isPaid: conv.contacts?.contacts?.[0]?.role === 'user'
  };
} else if (body.ticket || body.ticket_event) {
  // Zendesk format
  const ticket = body.ticket || {};
  normalized = {
    source: 'zendesk',
    externalId: `ZD-${ticket.id}`,
    email: ticket.requester?.email || ticket.email || '',
    name: ticket.requester?.name || '',
    message: ticket.description || '',
    subject: ticket.subject || '',
    tags: (ticket.tags || []).join(', '),
    isPaid: ticket.type === 'problem' || ticket.priority === 'high'
  };
} else if (body.payload?.event_type?.startsWith('slack')) {
  // Slack slash command or app mention
  const event = body.event || body.payload || {};
  normalized = {
    source: 'slack',
    externalId: event.ts || `SL-${Date.now()}`,
    email: body.userEmail || '',
    name: body.userName || event.user || '',
    message: event.text || body.text || '',
    subject: 'Slack Support Request',
    tags: '',
    isPaid: false
  };
} else {
  // Generic web form
  normalized = {
    source: body.source || 'web-form',
    externalId: body.id || `WF-${Date.now()}`,
    email: body.email || '',
    name: body.name || `${body.firstName || ''} ${body.lastName || ''}`.trim(),
    message: body.message || body.description || '',
    subject: body.subject || 'Support Request',
    tags: body.tags || '',
    isPaid: body.planType === 'paid' || body.subscription === 'pro'
  };
}

// Determine tier: paid users get priority routing
const tier = normalized.isPaid ? 'paid' : 'free';
const urgencyKeywords = ['urgent', 'critical', 'asap', 'broken', 'down', 'not working', 'emergency', 'immediately'];
const isUrgent = urgencyKeywords.some(kw => normalized.message.toLowerCase().includes(kw) || normalized.subject.toLowerCase().includes(kw));

normalized.tier = tier;
normalized.isUrgent = isUrgent;
normalized.routingKey = `${tier}-${normalized.source}`;
normalized.timestamp = new Date().toISOString();

return [{ json: normalized }];

parameters.responseBody:
={
  "success": true,
  "ticketId": "{{ $json.externalId }}",
  "tier": "{{ $json.tier }}",
  "message": "Support request received. Confirmation sent to {{ $json.email }}."
}
